SELECT [VendutoCompratoProiezione-step6-VenditeProiettate].No_, [VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code], [VendutoCompratoProiezione-step6-VenditeProiettate].PairsSold, 0 AS PairsPurchased, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarket_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsFlat, [VendutoCompratoProiezione-step6-VenditeProiettate].pairssold AS toBuy, 0 AS toSell, [VendutoCompratoProiezione-step6-VenditeProiettate].[ForecastedPairsByMarketCorrected_] AS toBuyByBudgetCorrected, 0 AS toSellByBudgetCorrected, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsFlat AS toBuyFlat, 0 AS toSellFlat
FROM [VendutoCompratoProiezione-step6-VenditeProiettate] LEFT JOIN [VendutoCompratoProiezione-step8-CompratoByAricoloColore] ON ([VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code] = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step6-VenditeProiettate].No_ = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_)
WHERE ((([VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_) Is Null));

